module.exports = "<!-- ══ Header ══════════════════════════════════════════════════ -->\n<ds-header>\n  <span slot=\"logo\" [innerHTML]=\"headerIcons.logo\"></span>\n  <span slot=\"app-name\">Qirin</span>\n\n  <ng-container slot=\"tabs\">\n    <ds-tab tone=\"reversed\" [selected]=\"true\">Home</ds-tab>\n    <ds-tab tone=\"reversed\">Buyers</ds-tab>\n    <ds-tab tone=\"reversed\">Policies</ds-tab>\n    <ds-tab tone=\"reversed\">Tools</ds-tab>\n    <ds-tab tone=\"reversed\">Configuration</ds-tab>\n  </ng-container>\n\n  <ng-container slot=\"actions\">\n    <ds-button-icon type=\"tertiary\" [reversed]=\"true\" size=\"s\" ariaLabel=\"Rechercher\">\n      <span [innerHTML]=\"headerIcons.search\"></span>\n    </ds-button-icon>\n    <ds-button-icon type=\"tertiary\" [reversed]=\"true\" size=\"s\" ariaLabel=\"Aide\">\n      <span [innerHTML]=\"headerIcons.help\"></span>\n    </ds-button-icon>\n    <ds-button-icon type=\"tertiary\" [reversed]=\"true\" size=\"s\" ariaLabel=\"Notifications\">\n      <span [innerHTML]=\"headerIcons.bell\"></span>\n    </ds-button-icon>\n  </ng-container>\n\n  <ng-container slot=\"account\">\n    <ds-tab tone=\"reversed\">\n      <span [innerHTML]=\"headerIcons.user\"></span>\n      John Doe\n    </ds-tab>\n  </ng-container>\n</ds-header>\n\n<!-- ══ Layout principal ════════════════════════════════════════ -->\n<div class=\"home-layout\">\n\n  <!-- ── Side Nav (collapsed) ────────────────────────────────── -->\n  <ds-side-nav [collapsed]=\"true\">\n    <ds-side-nav-item [selected]=\"true\">\n      <span slot=\"icon\" [innerHTML]=\"navIcons.home\"></span>\n    </ds-side-nav-item>\n    <ds-side-nav-item>\n      <span slot=\"icon\" [innerHTML]=\"navIcons.file\"></span>\n    </ds-side-nav-item>\n    <ds-side-nav-item>\n      <span slot=\"icon\" [innerHTML]=\"navIcons.chart\"></span>\n    </ds-side-nav-item>\n    <ds-side-nav-item>\n      <span slot=\"icon\" [innerHTML]=\"navIcons.person\"></span>\n    </ds-side-nav-item>\n    <ds-side-nav-item>\n      <span slot=\"icon\" [innerHTML]=\"navIcons.tools\"></span>\n    </ds-side-nav-item>\n    <ds-side-nav-item>\n      <span slot=\"icon\" [innerHTML]=\"navIcons.grid\"></span>\n    </ds-side-nav-item>\n  </ds-side-nav>\n\n  <!-- ── Contenu principal ────────────────────────────────────── -->\n  <main class=\"home-main\">\n\n    <!-- Hero section -->\n    <section class=\"home-hero\">\n      <div class=\"home-hero__content\">\n        <p class=\"home-hero__welcome\">Welcome back, John</p>\n        <h1 class=\"home-hero__title\">What would you like to work on today?</h1>\n        <p class=\"home-hero__subtitle\">\n          Pick an action below to get started, or explore your dashboard\n          for a complete overview of your activity.\n        </p>\n        <div class=\"home-hero__search\">\n          <ds-input-text placeholder=\"Search for a buyer\" [(value)]=\"searchValue\" />\n          <ds-button type=\"primary\">Search</ds-button>\n        </div>\n      </div>\n\n      <div class=\"home-hero__illustration\" aria-hidden=\"true\">\n        <div class=\"home-hero__illustration-placeholder\"></div>\n      </div>\n    </section>\n\n    <!-- Action cards -->\n    <section class=\"home-actions\">\n      @for (card of actionCards; track card.title) {\n        <ds-action-card\n          [title]=\"card.title\"\n          [description]=\"card.description\"\n          [linkLabel]=\"card.linkLabel\"\n        >\n          <span slot=\"icon\" [innerHTML]=\"card.iconSvg\"></span>\n        </ds-action-card>\n      }\n    </section>\n\n  </main>\n</div>\n";

